sqlMap.select:
/*BcjisComm.selectCommComboListOfficeCd*/ SELECT A.FIS_YEAR || '_' || A.BGT_DGR AS GROUP_ID , A.OFFICE_CD AS CODE , A.OFFICE_NM AS CODE_NM FROM TB_DGRDEPT A WHERE 1 = 1
AND EXISTS (SELECT 1 FROM TB_USERDEPT Z WHERE Z.USER_ID = #userId# AND Z.DEPT_CD = A.DEPT_CD AND Z.USE_YN = 'Y' AND ROWNUM = 1 )
GROUP BY A.FIS_YEAR , A.BGT_DGR , A.OFFICE_CD , A.OFFICE_NM ORDER BY A.FIS_YEAR DESC , A.BGT_DGR DESC , A.OFFICE_RANK ASC

/*BcjisComm.selectDeptUserYn*/ SELECT NVL((SELECT CASE WHEN COUNT(1) > 0 THEN 'N' ELSE 'Y' END FROM TB_USERREPORT Z WHERE 1 = 1 AND Z.USER_ID = #userId#
AND Z.REPORT_CD = #reportCd#
AND Z.USE_YN = 'Y' ) , 'Y') AS USER_DEPT_YN
